import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Paths;

public class SecureFileReadExample {

    public static void main(String[] args) {
        String filename = "sensitiveFile.txt"; // User input not properly sanitized

        // Sanitize user input to prevent path traversal
        filename = Paths.get(filename).getFileName().toString();

        try {
            BufferedReader br = new BufferedReader(new FileReader("data/" + filename));
            String line;
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }
            br.close();
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

